package library;

import library.Models.Loan;

import java.sql.SQLException;
import java.time.LocalDate;
import java.util.List;

/**
 * Demonstrates the library system end to end: sets up a catalog,
 * registers members, checks books in and out, and prints reports
 * generated by real SQL JOIN/GROUP BY queries.
 *
 * Run with: java -cp <classpath> library.Main
 */
public class Main {
    public static void main(String[] args) throws SQLException {
        Database db = new Database("library.db");
        LibraryService service = new LibraryService(db);

        int book1 = service.addBook("Clean Code", "Robert C. Martin", "978-0132350884", 2);
        int book2 = service.addBook("The Pragmatic Programmer", "Andrew Hunt", "978-0135957059", 1);

        int member1 = service.addMember("Rameen", "rameen@example.com", 3);
        int member2 = service.addMember("Alex", "alex@example.com", 1);

        LocalDate today = LocalDate.now();

        int loan1 = service.checkoutBook(member1, book1, today);
        System.out.println("Checked out 'Clean Code' to Rameen, loan id: " + loan1);

        service.checkoutBook(member1, book2, today);
        System.out.println("Checked out 'The Pragmatic Programmer' to Rameen");

        try {
            service.checkoutBook(member2, book2, today);
        } catch (LibraryService.BookUnavailableException e) {
            System.out.println("Expected failure: " + e.getMessage());
        }

        System.out.println("\nRameen's active loans:");
        List<Loan> active = service.activeLoansForMember(member1);
        for (Loan loan : active) {
            System.out.println("  " + loan.bookTitle() + " (due " + loan.dueDate() + ")");
        }

        service.returnBook(loan1, today);
        System.out.println("\nReturned 'Clean Code'.");

        System.out.println("\nMost borrowed books:");
        for (Object[] row : service.mostBorrowedBooks(5)) {
            System.out.println("  " + row[0] + " by " + row[1] + " -- borrowed " + row[2] + " time(s)");
        }

        db.close();
    }
}
